// Real nickname lookup needs a live call to the game's official/third-party
// "check role" endpoint through a backend (can't be faked reliably offline).
// This preview only validates the ID's format so it never shows a wrong name.
function verifyGameIdFormat(gameId) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (!gameId || gameId.length < 6 || !/^\d+$/.test(gameId)) {
        reject(new Error("Game ID ပုံစံ မှားနေပါသည်"));
      } else {
        resolve(true);
      }
    }, 700);
  });
}

function fmt(n) {
  return n.toLocaleString("en-US");
}

// Clipboard helper with a manual-copy fallback for sandboxed environments
// where navigator.clipboard may be blocked.
function copyText(text, onDone) {
  const fallback = () => {
    try {
      const ta = document.createElement("textarea");
      ta.value = text;
      ta.style.position = "fixed";
      ta.style.opacity = "0";
      document.body.appendChild(ta);
      ta.focus();
      ta.select();
      document.execCommand("copy");
      document.body.removeChild(ta);
      onDone(true);
    } catch (e) {
      onDone(false);
    }
  };
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(text).then(() => onDone(true)).catch(fallback);
  } else {
    fallback();
  }
}

