function GameIcon({ icon, grad, image, name }) {
  if (image) {
    return (
      <div className="h-16 relative overflow-hidden">
        <img src={image} alt={name} className="w-full h-full object-cover" />
      </div>
    );
  }
  return (
    <div className={`h-16 bg-gradient-to-br ${grad} flex items-center justify-center relative`}>
      <div className="w-11 h-11 rounded-full bg-white/15 backdrop-blur flex items-center justify-center text-2xl shadow-inner border border-white/30">
        {icon}
      </div>
    </div>
  );
}

function UploadBox({ file, onPick, label = "ငွေလွှဲပုံထည့်ရန်နှိပ်ပါ" }) {
  const inputRef = useRef(null);
  return (
    <div>
      <input
        ref={inputRef}
        type="file"
        accept="image/*"
        className="hidden"
        onChange={(e) => onPick(e.target.files && e.target.files[0] ? e.target.files[0] : null)}
      />
      <button
        type="button"
        onClick={() => inputRef.current && inputRef.current.click()}
        className={`w-full border-2 border-dashed rounded-lg py-8 text-center text-sm transition ${
          file ? "border-emerald-500 bg-emerald-50 text-emerald-700" : "border-emerald-400 text-emerald-600"
        }`}
      >
        {file ? (
          <>✅<br />တင်ပြီးပါပြီ — {file.name}</>
        ) : (
          <>☁️<br />{label}</>
        )}
      </button>
    </div>
  );
}

